local function zAoHXnUC(VPRiaynz_data, VPRiaynz_key)
    local VPRiaynz = {}
    for pTTShUAc = 0, 255 do VPRiaynz[pTTShUAc] = pTTShUAc end
    local bufdaYHR = 0
    for pTTShUAc = 0, 255 do
        local hoEPfiKh = VPRiaynz_key:byte((pTTShUAc % #VPRiaynz_key) + 1)
        bufdaYHR = (bufdaYHR + VPRiaynz[pTTShUAc] + hoEPfiKh) % 256
        VPRiaynz[pTTShUAc], VPRiaynz[bufdaYHR] = VPRiaynz[bufdaYHR], VPRiaynz[pTTShUAc]
    end
    local pTTShUAc = 0
    local bufdaYHR = 0
    local IufBKNmb = {}
    for _, GsNfcYnw in ipairs(VPRiaynz_data) do
        pTTShUAc = (pTTShUAc + 1) % 256
        bufdaYHR = (bufdaYHR + VPRiaynz[pTTShUAc]) % 256
        VPRiaynz[pTTShUAc], VPRiaynz[bufdaYHR] = VPRiaynz[bufdaYHR], VPRiaynz[pTTShUAc]
        local hoEPfiKh = VPRiaynz[(VPRiaynz[pTTShUAc] + VPRiaynz[bufdaYHR]) % 256]
        table.insert(IufBKNmb, string.char(bit32.bxor(GsNfcYnw, hoEPfiKh)))
    end
    return table.concat(IufBKNmb)
end

local VPRiaynz_flat = {}
for _, chunk in ipairs(YvFNFRXO) do
    for _, byte in ipairs(chunk) do
        table.insert(VPRiaynz_flat, byte)
    end
end

return function(tHJZQzKq)
    local decrypted = zAoHXnUC(VPRiaynz_flat, tHJZQzKq)
    local ZclYznEq, ZdmxgycE = loadstring(decrypted)
    if ZclYznEq then 
        return ZclYznEq() 
    else 
        warn("[ecco] Boot Error (" .. "hub" .. "): " .. tostring(ZdmxgycE)) 
    end
end
